import{_ as o,a,b as t,c as l}from"./chunks/授权完复制token.D-mju0qq.js";import{_ as i,o as r,c as d,a2 as s}from"./chunks/framework.DnrXFDHb.js";const v=JSON.parse('{"title":"Google Drive 渠道添加说明","description":"","frontmatter":{},"headers":[],"relativePath":"cn/upload/google-drive.md","filePath":"cn/upload/google-drive.md","lastUpdated":1781962217000}'),n={name:"cn/upload/google-drive.md"};function c(p,e,h,g,u,b){return r(),d("div",null,[...e[0]||(e[0]=[s('<h1 id="google-drive-渠道添加说明" tabindex="-1">Google Drive 渠道添加说明 <a class="header-anchor" href="#google-drive-渠道添加说明" aria-label="Permalink to &quot;Google Drive 渠道添加说明&quot;">​</a></h1><h2 id="添加前要准备什么" tabindex="-1">添加前要准备什么 <a class="header-anchor" href="#添加前要准备什么" aria-label="Permalink to &quot;添加前要准备什么&quot;">​</a></h2><p>在开始之前，你只需要准备这 4 样：</p><table tabindex="0"><thead><tr><th>需要准备</th><th>用途</th></tr></thead><tbody><tr><td>一个 Google 账号</td><td>用来登录 Google Cloud，并授权你的 Google Drive</td></tr><tr><td>一个 Google Cloud 项目</td><td>用来启用 Drive API，并创建 OAuth 2.0 凭据</td></tr><tr><td>OAuth 2.0 客户端</td><td>系统通过它获取 <code>Client ID</code>、<code>Client Secret</code> 和 <code>Refresh Token</code></td></tr><tr><td>当前图床访问域名</td><td>用来配置授权回调地址，必须和系统实际访问域名一致</td></tr></tbody></table><h2 id="添加步骤" tabindex="-1">添加步骤 <a class="header-anchor" href="#添加步骤" aria-label="Permalink to &quot;添加步骤&quot;">​</a></h2><h3 id="第一步-登录-google-cloud-并启用-google-drive-api" tabindex="-1">第一步：登录 Google Cloud 并启用 Google Drive API <a class="header-anchor" href="#第一步-登录-google-cloud-并启用-google-drive-api" aria-label="Permalink to &quot;第一步：登录 Google Cloud 并启用 Google Drive API&quot;">​</a></h3><p>操作顺序如下：</p><ol><li>打开 Google Cloud Console。</li><li>新建一个项目，或者直接选择你现有的项目。</li><li>进入 <code>APIs &amp; Services</code>。</li><li>点击 <code>Enable APIs and Services</code>。</li><li>搜索 <code>Google Drive API</code>。</li><li>点进去后点击启用。</li></ol><h3 id="第二步-配置-oauth-同意页面" tabindex="-1">第二步：配置 OAuth 同意页面 <a class="header-anchor" href="#第二步-配置-oauth-同意页面" aria-label="Permalink to &quot;第二步：配置 OAuth 同意页面&quot;">​</a></h3><p>操作顺序如下：</p><ol><li>在 Google Cloud 里进入 <code>Google Auth Platform</code>。</li><li>先完成 <code>Branding</code> 里的基础信息，例如应用名称、支持邮箱、开发者联系邮箱。</li><li>进入 <code>Audience</code>。</li><li>大多数个人部署场景，直接选 <code>External</code> 就行。</li><li>如果你选的是 <code>External</code>，再把你自己要授权的 Google 账号加到 <code>Test users</code>。</li><li>进入 <code>Data Access</code>。</li><li>添加 Google Drive 权限。</li></ol><h3 id="第三步-创建-oauth-2-0-客户端" tabindex="-1">第三步：创建 OAuth 2.0 客户端 <a class="header-anchor" href="#第三步-创建-oauth-2-0-客户端" aria-label="Permalink to &quot;第三步：创建 OAuth 2.0 客户端&quot;">​</a></h3><p>操作顺序如下：</p><ol><li>进入 <code>Google Auth Platform</code> 的 <code>Clients</code>。</li><li>点击创建客户端。</li><li>应用类型选择 <code>Web application</code>。</li><li>给这套客户端起一个你自己能认出来的名字。 5.已获授权的 JavaScript 来源填写你的图床地址：<a href="https://img.example.com" target="_blank" rel="noreferrer">https://img.example.com</a> 6.已获授权的重定向 URI 来源填写你的图床回调：<a href="https://img.example.com/api/oauth/google/callback" target="_blank" rel="noreferrer">https://img.example.com/api/oauth/google/callback</a></li></ol><p><img src="'+o+'" alt="创建 OAuth 客户端" loading="lazy"></p><p><img src="'+a+'" alt="填写图床域名和回调地址" loading="lazy"></p><p>创建完成以后，复制保存这两个值：</p><table tabindex="0"><thead><tr><th>生成结果</th><th>后面填到哪里</th></tr></thead><tbody><tr><td>Client ID</td><td>系统里的 <code>Client ID</code></td></tr><tr><td>Client Secret</td><td>系统里的 <code>Client Secret</code></td></tr></tbody></table><h2 id="第四步-回到系统里填写-google-drive-渠道" tabindex="-1">第四步：回到系统里填写 Google Drive 渠道 <a class="header-anchor" href="#第四步-回到系统里填写-google-drive-渠道" aria-label="Permalink to &quot;第四步：回到系统里填写 Google Drive 渠道&quot;">​</a></h2><p>在上传设置里选择 <code>Google Drive</code> 后，按下面这套填：</p><table tabindex="0"><thead><tr><th>页面字段</th><th>你该填什么</th></tr></thead><tbody><tr><td>渠道名称</td><td>你自己起，比如 <code>GoogleDrive主账号</code></td></tr><tr><td>Client ID</td><td>刚才在 Google Cloud 创建出来的 Client ID</td></tr><tr><td>Client Secret</td><td>刚才在 Google Cloud 创建出来的 Client Secret</td></tr><tr><td>Refresh Token</td><td>先可以留空，下一步通过系统按钮获取</td></tr><tr><td>根目录</td><td>可选，默认是 <code>imgbed</code></td></tr></tbody></table><p><img src="'+t+'" alt="把客户端信息先填回系统" loading="lazy"></p><h2 id="第五步-在系统里获取-refresh-token" tabindex="-1">第五步：在系统里获取 Refresh Token <a class="header-anchor" href="#第五步-在系统里获取-refresh-token" aria-label="Permalink to &quot;第五步：在系统里获取 Refresh Token&quot;">​</a></h2><ol><li>点击 <code>获取令牌</code>。</li><li>选择你要绑定的 Google 账号。</li><li>按页面提示完成授权。</li><li>成功后，回调页会显示一串 <code>Refresh Token</code>。</li><li>复制它。</li><li>回到系统，把它粘贴到 <code>Refresh Token</code> 输入框里。</li></ol><p><img src="'+l+`" alt="授权成功后复制 Refresh Token" loading="lazy"></p><p>如果你后面换了 Google 账号、改了客户端、或者旧授权失效了，也不用删渠道，直接点编辑页里的 <code>重新授权</code> 就行。</p><h2 id="第六步-保存渠道配置" tabindex="-1">第六步：保存渠道配置 <a class="header-anchor" href="#第六步-保存渠道配置" aria-label="Permalink to &quot;第六步：保存渠道配置&quot;">​</a></h2><p>字段填好以后，直接点击保存。</p><h2 id="渠道的操作流程总结" tabindex="-1">渠道的操作流程总结 <a class="header-anchor" href="#渠道的操作流程总结" aria-label="Permalink to &quot;渠道的操作流程总结&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>登录 Google Cloud</span></span>
<span class="line"><span>-&gt; 新建或选择项目</span></span>
<span class="line"><span>-&gt; 启用 Google Drive API</span></span>
<span class="line"><span>-&gt; 配置 Google Auth Platform</span></span>
<span class="line"><span>-&gt; Audience 选 External 时，把自己的 Google 账号加进 Test users</span></span>
<span class="line"><span>-&gt; 创建 Web application 类型的 OAuth 客户端</span></span>
<span class="line"><span>-&gt; 回调地址填写 https://你的域名/api/oauth/google/callback</span></span>
<span class="line"><span>-&gt; 回系统填 Client ID 和 Client Secret</span></span>
<span class="line"><span>-&gt; 点击 获取令牌</span></span>
<span class="line"><span>-&gt; Google 登录并授权</span></span>
<span class="line"><span>-&gt; 复制回调页里的 Refresh Token</span></span>
<span class="line"><span>-&gt; 粘回系统并保存</span></span>
<span class="line"><span>-&gt; 上传测试图</span></span></code></pre></div><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ol><li>Google OAuth Web Server Applications：<a href="https://developers.google.com/identity/protocols/oauth2/web-server" target="_blank" rel="noreferrer">https://developers.google.com/identity/protocols/oauth2/web-server</a></li><li>Google Workspace OAuth Consent Configuration：<a href="https://developers.google.com/workspace/guides/configure-oauth-consent" target="_blank" rel="noreferrer">https://developers.google.com/workspace/guides/configure-oauth-consent</a></li><li>Google Drive API Auth Scope 说明：<a href="https://developers.google.com/workspace/drive/api/guides/api-specific-auth" target="_blank" rel="noreferrer">https://developers.google.com/workspace/drive/api/guides/api-specific-auth</a></li></ol>`,32)])])}const k=i(n,[["render",c]]);export{v as __pageData,k as default};
